效果展示 默认折叠 查看详情 需要折叠的内容
print(&#39;hello world&#39;) {{&lt; details summary=&#34;查看详情&#34; &gt;}} 需要折叠的内容 ```python print(&#39;hello world&#39;) ``` {{&lt; /details &gt;}} 默认展开 查看详情 需要折叠的内容
print(&#39;hello world&#39;) {{&lt; details summary=&#34;查看详情&#34; open=true &gt;}} 需要折叠的内容 ```python print(&#39;hello world&#39;) ``` {{&lt; /details &gt;}} 具体实现 shortcode layouts/shortcodes/details.html {{- $summary := .Get &#34;summary&#34; | default (.Get &#34;title&#34;) -}} {{- if not $summary -}} {{- warnf &#34;missing value for param &#39;summary&#39;: %s&#34; .Position -}} {{- end -}} {{- $open := .Get &#34;open&#34; | default true -}} &lt;details class=&#34;post-details shortcode-details&#34;{{ if $open }} open{{ end }}&gt; &lt;summary class=&#34;post-details-summary&#34;&gt; {{- $summary | markdownify -}} &lt;/summary&gt; &lt;div class=&#34;post-details-content&#34;&gt; {{- .Inner | markdownify -}} &lt;/div&gt; &lt;/details&gt; CSS assets/css/extended/shortcodes.css .shortcode-details { margin: 1rem 0; border: 1px solid var(--border); border-radius: 8px; background: var(--entry); overflow: hidden; } .shortcode-details &gt; summary { cursor: pointer; padding: 0.75rem 1rem; font-weight: 600; user-select: none; background: var(--code-bg); } .shortcode-details &gt; summary:hover { background: rgba(128, 128, 128, 0.12); } .post-details-content { padding: 1rem; } .post-details-content &gt; :first-child { margin-top: 0; } .post-details-content &gt; :last-child { margin-bottom: 0; } .post-details-content pre { margin-top: 0.75rem; margin-bottom: 0.75rem; }
